"use strict";(self.webpackChunktemp_blog=self.webpackChunktemp_blog||[]).push([["454"],{6239(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/rman-log-check","metadata":{"permalink":"/engineering-devlog/blog/rman-log-check","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/rman-log-check.md","source":"@site/blog/rman-log-check.md","title":"rman-log-check","description":"---","date":"2026-07-09T11:24:33.000Z","tags":[],"readingTime":0.61,"hasTruncateMarker":false,"authors":[],"frontMatter":{},"unlisted":false},"content":"---\\nslug: first-production-hotfix\\ntitle: RMAN backup failure and logs check\\nauthors: [VikasPadmashali123]\\ntags: [Rman, backup, logs]\\n---\\n###This post has details of RMAN backup status and logs\\n\\n\\nCheck RMAN backup status and rman backup logs: \\n\\nSTEP 1:  To find the status of the jobs:\\n\\nset lines 300\\n col STATUS format a22\\n col hrs format 999.99\\n select\\n SESSION_KEY, SESSION_RECID, SESSION_STAMP,INPUT_TYPE, STATUS,\\n to_char(START_TIME,\'mm/dd/yy hh24:mi\') start_time,\\n to_char(END_TIME,\'mm/dd/yy hh24:mi\')   end_time,\\n elapsed_seconds/3600                   hrs\\n from V$RMAN_BACKUP_JOB_DETAILS\\n where status=\'RUNNING\'\\n order by session_key;\\n\\n\\nSTEP 2: Check the logs or output of the running RMAN jobs \\nset lines 200\\n set pages 1000\\n select output from GV$RMAN_OUTPUT\\n where session_recid = &SESSION_RECID\\n and session_stamp = &SESSION_STAMP\\n order by recid;"}]}}')}}]);